import React, { useState, useEffect, useRef } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { practiceAPI, progressAPI } from '../services/api';

const PracticeSession = () => {
  const { sessionNumber } = useParams();
  const navigate = useNavigate();

  const [sessionData, setSessionData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  // Typing state
  const [userInput, setUserInput] = useState('');
  const [startTime, setStartTime] = useState(null);
  const [timeElapsed, setTimeElapsed] = useState(0);
  const [isComplete, setIsComplete] = useState(false);
  const [showResults, setShowResults] = useState(false);

  const inputRef = useRef(null);
  const timerRef = useRef(null);
  const contentRef = useRef(null);

  useEffect(() => {
    fetchSession();
    return () => {
      if (timerRef.current) {
        clearInterval(timerRef.current);
      }
    };
  }, [sessionNumber]);

  useEffect(() => {
    if (inputRef.current && !isComplete) {
      inputRef.current.focus();
    }
  }, [isComplete]);

  const fetchSession = async () => {
    try {
      const response = await practiceAPI.getByNumber(sessionNumber);
      setSessionData(response.data);
    } catch (err) {
      console.error('Error fetching practice session:', err);
      setError('Failed to load practice session');
    } finally {
      setLoading(false);
    }
  };

  const startTimer = () => {
    if (!startTime) {
      const now = Date.now();
      setStartTime(now);
      timerRef.current = setInterval(() => {
        const elapsed = (Date.now() - now) / 1000;
        setTimeElapsed(elapsed);

        // Auto-submit after duration
        if (elapsed >= sessionData.duration * 60) {
          handleSubmit();
        }
      }, 100);
    }
  };

  const calculateStats = () => {
    const content = sessionData.content;
    const timeInMinutes = timeElapsed / 60 || 0.1;
    const wordsTyped = userInput.trim().split(/\s+/).length;
    const wpm = Math.round(wordsTyped / timeInMinutes);

    // Calculate accuracy by comparing typed text with content
    let correctChars = 0;
    const minLength = Math.min(userInput.length, content.length);

    for (let i = 0; i < minLength; i++) {
      if (userInput[i] === content[i]) {
        correctChars++;
      }
    }

    const accuracy = Math.round((correctChars / Math.max(userInput.length, 1)) * 100);

    return { 
      wpm, 
      accuracy, 
      timeElapsed: Math.round(timeElapsed),
      wordsTyped,
      totalWords: content.split(/\s+/).length
    };
  };

  const handleSubmit = async () => {
    if (timerRef.current) {
      clearInterval(timerRef.current);
    }

    const stats = calculateStats();

    try {
      await progressAPI.submitPractice({
        sessionNumber: parseInt(sessionNumber),
        wpm: stats.wpm,
        accuracy: stats.accuracy
      });

      setIsComplete(true);
      setShowResults(true);
    } catch (err) {
      console.error('Error submitting progress:', err);
      alert('Failed to save progress. Please try again.');
    }
  };

  const handleInputChange = (e) => {
    const value = e.target.value;

    if (!startTime) {
      startTimer();
    }

    setUserInput(value);

    // Check if user has typed everything
    if (value.length >= sessionData.content.length) {
      handleSubmit();
    }
  };

  const formatTime = (seconds) => {
    const mins = Math.floor(seconds / 60);
    const secs = Math.floor(seconds % 60);
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const getTimeRemaining = () => {
    const totalTime = sessionData.duration * 60;
    const remaining = Math.max(0, totalTime - timeElapsed);
    return formatTime(remaining);
  };

  if (loading) {
    return <div className="loading">Loading practice session...</div>;
  }

  if (error || !sessionData) {
    return (
      <div className="container">
        <div className="error">{error || 'Session not found'}</div>
        <button className="btn btn-primary" onClick={() => navigate('/practice')}>
          Back to Practice
        </button>
      </div>
    );
  }

  const stats = showResults ? calculateStats() : null;

  return (
    <div className="container">
      <div className="typing-interface">
        <div className="typing-header">
          <div>
            <h3>Practice Session {sessionData.sessionNumber}</h3>
            <p style={{ color: '#666' }}>{sessionData.title}</p>
          </div>
          <div className="typing-stats">
            <div className="stat-item">
              <span>Time Remaining</span>
              <strong style={{ color: timeElapsed >= sessionData.duration * 60 * 0.9 ? '#dc3545' : '#667eea' }}>
                {getTimeRemaining()}
              </strong>
            </div>
            <div className="stat-item">
              <span>Progress</span>
              <strong>
                {Math.round((userInput.length / sessionData.content.length) * 100)}%
              </strong>
            </div>
            <div className="stat-item">
              <span>Words</span>
              <strong>
                {userInput.trim().split(/\s+/).length} / {sessionData.minWords}
              </strong>
            </div>
          </div>
        </div>

        <div className="typing-content" ref={contentRef} style={{ minHeight: '200px', fontSize: '1.3rem', lineHeight: '2' }}>
          {(() => {
            const content = sessionData.content;
            const charsPerLine = 80; // Approximate characters per line
            const visibleLines = 6; // Number of lines to show
            const charsToShow = charsPerLine * visibleLines;

            // Calculate which portion to show based on user's progress
            const startIndex = Math.max(0, userInput.length - Math.floor(charsToShow / 2));
            const endIndex = Math.min(content.length, startIndex + charsToShow);

            return content.split('').slice(startIndex, endIndex).map((char, relativeIndex) => {
              const actualIndex = startIndex + relativeIndex;
              let className = '';

              if (actualIndex < userInput.length) {
                className = userInput[actualIndex] === char ? 'correct' : 'incorrect';
              } else if (actualIndex === userInput.length) {
                className = 'current';
              }

              return (
                <span key={actualIndex} className={className}>
                  {char}
                </span>
              );
            });
          })()}
        </div>

        {!isComplete && (
          <>
            <textarea
              ref={inputRef}
              className="typing-input"
              value={userInput}
              onChange={handleInputChange}
              placeholder="Start typing to begin the practice session..."
              style={{ height: '150px' }}
              autoFocus
            />
            <div style={{ display: 'flex', gap: '1rem', justifyContent: 'center' }}>
              <button className="btn btn-success" onClick={handleSubmit}>
                Submit Session
              </button>
              <button className="btn btn-secondary" onClick={() => navigate('/practice')}>
                Exit
              </button>
            </div>
          </>
        )}

        {showResults && stats && (
          <div className="results-modal">
            <div className="results-content">
              <h2>Practice Session Complete! 🎉</h2>
              <div className="results-stats">
                <div className="result-stat">
                  <h3>{stats.wpm}</h3>
                  <p>Words Per Minute</p>
                </div>
                <div className="result-stat">
                  <h3>{stats.accuracy}%</h3>
                  <p>Accuracy</p>
                </div>
                <div className="result-stat">
                  <h3>{formatTime(stats.timeElapsed)}</h3>
                  <p>Time Taken</p>
                </div>
                <div className="result-stat">
                  <h3>{stats.wordsTyped}</h3>
                  <p>Words Typed</p>
                </div>
              </div>
              <div className="results-actions">
                <button className="btn btn-primary" onClick={() => navigate('/practice')}>
                  Back to Practice
                </button>
                <button className="btn btn-secondary" onClick={() => navigate('/dashboard')}>
                  Dashboard
                </button>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default PracticeSession;
